let _timer = null;
let _dotNetRef = null;
let _isIdle = false;
let _timeoutMs = 300000;
let _wrapper = null;
const _events = ["mousemove", "keydown", "click", "scroll"];

function _onActivity() {
    if (_isIdle) {
        _isIdle = false;
        _dotNetRef.invokeMethodAsync("NotifyActive");
    }
    _resetTimer();
}

function _resetTimer() {
    clearTimeout(_timer);
    _timer = setTimeout(() => {
        _isIdle = true;
        _dotNetRef.invokeMethodAsync("NotifyIdle");
    }, _timeoutMs);
}

export function init(wrapper, dotNetRef, timeoutMs) {
    _wrapper = wrapper;
    _dotNetRef = dotNetRef;
    _timeoutMs = timeoutMs;
    _isIdle = false;

    for (const evt of _events) {
        _wrapper.addEventListener(evt, _onActivity, { passive: true });
    }
    _resetTimer();
}

export function dispose() {
    clearTimeout(_timer);
    if (_wrapper) {
        for (const evt of _events) {
            _wrapper.removeEventListener(evt, _onActivity);
        }
    }
    _wrapper = null;
    _dotNetRef = null;
}

